sql:
SELECT rule_name 
FROM data_validation_rules 
WHERE rule_name LIKE 'Required%' AND rule_severity = 'critical';

SELECT result
FROM validation_results
WHERE rule_id = 0;

SELECT destination_type, destination_url
FROM data_destination
WHERE destination_name = 'Destination 2';

SELECT data_id, data_value, validation_status
FROM incoming_data
WHERE data_id = 1;

SELECT dr.rule_id, dr.rule_name, dt.template_id, dt.template_name
FROM data_validation_rules AS dr
JOIN data_templates AS dt ON dr.rule_expression = dt.template_expression;

SELECT AVG(job_duration) AS average_job_duration
FROM data_processing_jobs
WHERE job_status = 'failed';

SELECT * 
FROM incoming_data
WHERE validation_status = 'validated' AND created_at > '2023-05-01 12:00:00';

SELECT job_status, job_error_message 
FROM data_processing_jobs 
WHERE job_id = 0;

SELECT AVG(job_duration) AS average_job_duration
FROM data_processing_jobs
WHERE job_type = 'batch' AND job_status = 'failed';

SELECT DISTINCT rule_name
FROM data_validation_rules
WHERE rule_type = 'required digit' AND rule_enabled = 1;
